using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Web;
using sv_f5682af3b1294e1da12d03bd2f80a506.Services;

namespace sv_f5682af3b1294e1da12d03bd2f80a506.Components.Pages;

public partial class Chat
{
    private List<Channel>? channels;
    private Channel? activeChannel;
    private int activeChannelId;
    private List<Message>? messages;
    private Dictionary<int, ThreadSummary> threadSummaries = new();
    private bool isLoadingMore;
    private int messageSkip;
    private const int PageSize = 30;

    private string newMessageContent = string.Empty;
    private int? hoveredMessageId;
    private int? emojiPickerMessageId;

    private bool threadOpen;
    private Message? threadRootMessage;
    private List<Message>? threadMessages;
    private string threadReplyContent = string.Empty;

    private ElementReference messageListRef;

    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannelAsync(channels[0]);
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        activeChannel = channel;
        activeChannelId = channel.Id;
        messageSkip = 0;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        messageSkip = messages.Count;
        await ChatService.MarkChannelReadAsync(channel.Id);
        BuildThreadSummaries();
        StateHasChanged();
    }

    private void BuildThreadSummaries()
    {
        threadSummaries.Clear();
        if (messages is null) return;

        var replies = messages.Where(m => m.ReplyToId.HasValue).ToList();
        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt)
            );
        }
    }

    private async Task HandleScrollAsync()
    {
        // Pagination triggered via scroll-to-top (JS interop would be needed for precise detection).
        // Simplified: load more if at top of list.
    }

    public async Task LoadOlderMessagesAsync()
    {
        if (isLoadingMore || activeChannel is null) return;
        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannel.Id, messageSkip, PageSize);
        if (older.Count > 0)
        {
            messages = older.Concat(messages ?? []).ToList();
            messageSkip += older.Count;
            BuildThreadSummaries();
        }

        isLoadingMore = false;
        StateHasChanged();
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageContent) || activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(activeChannel.Id, newMessageContent.Trim(), null);
        messages ??= [];
        messages.Add(sent);
        newMessageContent = string.Empty;
        StateHasChanged();
    }

    private async Task HandleMessageKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessageAsync();
        }
    }

    private async Task OpenThreadAsync(int rootMessageId)
    {
        threadRootMessage = messages?.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        threadMessages = await ChatService.GetThreadAsync(rootMessageId);
        threadOpen = true;
        threadReplyContent = string.Empty;
        emojiPickerMessageId = null;
        StateHasChanged();
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadMessages = null;
        threadReplyContent = string.Empty;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyContent) || threadRootMessage is null || activeChannel is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannel.Id, threadReplyContent.Trim(), threadRootMessage.Id);
        threadMessages ??= [];
        threadMessages.Add(reply);
        threadReplyContent = string.Empty;
        BuildThreadSummaries();
        StateHasChanged();
    }

    private async Task HandleThreadKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendThreadReplyAsync();
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        emojiPickerMessageId = null;

        // Refresh messages to show updated reactions
        if (activeChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(activeChannel.Id, 0, messageSkip);
        }
        StateHasChanged();
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string description)
    {
        return description.Length > 40 ? description[..37] + "..." : description;
    }
}

